// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Card, CardContent } from "@/components/ui/card";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";

// constants
const members = [
  {
    name: "Shirley Hoe",
    role: "Professional",
    bio: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    avatar: "https://cdn.uiable.com/block/team1.png",
    initials: "SH",
  },
  {
    name: "Joseph William",
    role: "Professional",
    bio: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    avatar: "https://cdn.uiable.com/block/team2.png",
    initials: "JW",
  },
  {
    name: "John Doe",
    role: "Professional",
    bio: "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    avatar: "https://cdn.uiable.com/block/team3.png",
    initials: "JD",
  },
];

//  ------------------------------ | TEAM 1 | ------------------------------  //

export default function team1() {
  return (
    <section className="py-16">
      <div className="mx-auto container px-6">
        <div className="grid grid-cols-12 mb-12">
          <div className="col-span-12 text-center">
            <h2>Our Crew</h2>
            <p className="text-muted-foreground mt-3 mx-auto max-w-xl">
              At half-past eight the door opened, the policeman appeared and
              requesting them to follow him, led way to an adjoining hall.
            </p>
          </div>
        </div>

        <Carousel opts={{ align: "start", loop: true }} className="px-10">
          <CarouselContent>
            {members.map((member) => (
              <CarouselItem
                key={member.name}
                className="basis-full sm:basis-1/2 lg:basis-1/3"
              >
                <Card className="mb-0">
                  <CardContent className="flex flex-col items-center text-center p-8 gap-4">
                    <Avatar className="size-26!">
                      <AvatarImage src={member.avatar} alt={member.name} />
                      <AvatarFallback>{member.initials}</AvatarFallback>
                    </Avatar>
                    <div>
                      <h6 className="font-semibold text-foreground">
                        {member.name}
                      </h6>
                      <p className="text-muted-foreground text-sm mt-1">
                        {member.role}
                      </p>
                    </div>
                    <p className="text-muted-foreground text-md leading-relaxed">
                      {member.bio}
                    </p>
                  </CardContent>
                </Card>
              </CarouselItem>
            ))}
          </CarouselContent>
          <CarouselPrevious className="-left-6" />
          <CarouselNext className="-right-6" />
        </Carousel>
      </div>
    </section>
  );
}
